class DesktopChooseAddressFromStack extends ConsumerStatefulWidget {
  const DesktopChooseAddressFromStack({super.key, required this.coin});

  final CryptoCurrency coin;

  @override
  ConsumerState<DesktopChooseAddressFromStack> createState() =>
      _DesktopChooseFromStackState();
}

class _DesktopChooseFromStackState
    extends ConsumerState<DesktopChooseAddressFromStack> {
  late final TextEditingController _searchController;
  late final FocusNode searchFieldFocusNode;

  String _searchTerm = "";

  List<String> filter(List<String> walletIds, String searchTerm) {
    if (searchTerm.isEmpty) {
      return walletIds;
    }

    final List<String> result = [];
    for (final walletId in walletIds) {
      final name = ref.read(pWalletName(walletId));

      if (name.toLowerCase().contains(searchTerm.toLowerCase())) {
        result.add(walletId);
      }
    }

    return result;
  }

  @override
  void initState() {
    searchFieldFocusNode = FocusNode();
    _searchController = TextEditingController();
    super.initState();
  }

  @override
  void dispose() {
    _searchController.dispose();
    searchFieldFocusNode.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        Text(
          "Choose from ${AppConfig.prefix}",
          style: STextStyles.desktopH3(context),
        ),
        const SizedBox(height: 28),
        ClipRRect(
          borderRadius: BorderRadius.circular(
            Constants.size.circularBorderRadius,
          ),
          child: TextField(
            autocorrect: false,
            enableSuggestions: false,
            controller: _searchController,
            focusNode: searchFieldFocusNode,
            onChanged: (value) {
              setState(() {
                _searchTerm = value;
              });
            },
            style: STextStyles.desktopTextExtraSmall(context).copyWith(
              color: Theme.of(
                context,
              ).extension<StackColors>()!.textFieldActiveText,
              height: 1.8,
            ),
            decoration:
                standardInputDecoration(
                  "Search",
                  searchFieldFocusNode,
                  context,
                  desktopMed: true,
                ).copyWith(
                  prefixIcon: Padding(
                    padding: const EdgeInsets.symmetric(
                      horizontal: 12,
                      vertical: 18,
                    ),
                    child: SvgPicture.asset(
                      Assets.svg.search,
                      width: 20,
                      height: 20,
                    ),
                  ),
                  suffixIcon: _searchController.text.isNotEmpty
                      ? Padding(
                          padding: const EdgeInsets.only(right: 0),
                          child: UnconstrainedBox(
                            child: Row(
                              children: [
                                TextFieldIconButton(
                                  child: const XIcon(),
                                  onTap: () async {
                                    setState(() {
                                      _searchController.text = "";
                                      _searchTerm = "";
                                    });
                                  },
                                ),
                              ],
                            ),
                          ),
                        )
                      : null,
                ),
          ),
        ),
        const SizedBox(height: 16),
        Flexible(
          child: Builder(
            builder: (context) {
              final wallets = ref
                  .watch(pWallets)
                  .wallets
                  .where((e) => e.info.coin == widget.coin);

              if (wallets.isEmpty) {
                return Column(
                  children: [
                    RoundedWhiteContainer(
                      borderColor: Theme.of(
                        context,
                      ).extension<StackColors>()!.background,
                      child: Center(
                        child: Text(
                          "No ${widget.coin.ticker.toUpperCase()} wallets",
                          style: STextStyles.desktopTextExtraExtraSmall(
                            context,
                          ),
                        ),
                      ),
                    ),
                  ],
                );
              }

              List<String> walletIds = wallets.map((e) => e.walletId).toList();

              walletIds = filter(walletIds, _searchTerm);

              return ListView.separated(
                primary: false,
                itemCount: walletIds.length,
                separatorBuilder: (_, __) => const SizedBox(height: 5),
                itemBuilder: (context, index) =>
                    _WalletRow(walletId: walletIds[index]),
              );
            },
          ),
        ),
        const SizedBox(height: 20),
        Row(
          children: [
            const Spacer(),
            const SizedBox(width: 16),
            Expanded(
              child: SecondaryButton(
                label: "Cancel",
                buttonHeight: ButtonHeight.l,
                onPressed: Navigator.of(context).pop,
              ),
            ),
          ],
        ),
      ],
    );
  }
}

class _BalanceDisplay extends ConsumerWidget {
  const _BalanceDisplay({super.key, required this.walletId, this.balanceType});

  final String walletId;
  final BalanceType? balanceType;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final coin = ref.watch(pWalletCoin(walletId));
    final total = balanceType == BalanceType.public
        ? ref.watch(pWalletBalance(walletId)).total
        : balanceType == BalanceType.private
        ? ref.watch(pWalletBalanceSecondary(walletId)).total +
              ref.watch(pWalletBalanceTertiary(walletId)).total
        : ref.watch(pWalletBalance(walletId)).total +
              ref.watch(pWalletBalanceSecondary(walletId)).total +
              ref.watch(pWalletBalanceTertiary(walletId)).total;

    return Text(
      ref.watch(pAmountFormatter(coin)).format(total),
      style: STextStyles.desktopTextExtraSmall(context).copyWith(
        color: Theme.of(context).extension<StackColors>()!.textSubtitle1,
      ),
      textAlign: TextAlign.right,
    );
  }
}

class _WalletRow extends ConsumerWidget {
  const _WalletRow({super.key, required this.walletId});

  final String walletId;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final coin = ref.watch(pWalletCoin(walletId));

    if (coin is! Firo) {
      return RoundedWhiteContainer(
        borderColor: Theme.of(context).extension<StackColors>()!.background,
        padding: const EdgeInsets.symmetric(horizontal: 20, vertical: 14),
        child: Row(
          children: [
            Row(
              children: [
                WalletInfoCoinIcon(coin: coin),
                const SizedBox(width: 12),
                Text(
                  ref.watch(pWalletName(walletId)),
                  style: STextStyles.desktopTextExtraExtraSmall(context)
                      .copyWith(
                        color: Theme.of(
                          context,
                        ).extension<StackColors>()!.textDark,
                      ),
                ),
              ],
            ),
            const Spacer(),
            _BalanceDisplay(walletId: walletId),
            const SizedBox(width: 80),
            CustomTextButton(
              text: "Select wallet",
              onTap: () async {
                final wallet = ref.read(pWallets).getWallet(walletId);
                final address =
                    (await wallet.getCurrentReceivingAddress())?.value ??
                    wallet.info.cachedReceivingAddress;

                if (context.mounted) {
                  Navigator.of(context).pop(Tuple2(wallet.info.name, address));
                }
              },
            ),
          ],
        ),
      );
    }

    return RoundedWhiteContainer(
      borderColor: Theme.of(context).extension<StackColors>()!.background,
      padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 16),
      child: Column(
        mainAxisSize: .min,
        crossAxisAlignment: .start,
        children: [
          Row(
            children: [
              WalletInfoCoinIcon(coin: coin, size: 32),
              const SizedBox(width: 12),
              Text(
                ref.watch(pWalletName(walletId)),
                style: STextStyles.desktopTextExtraExtraSmall(context).copyWith(
                  color: Theme.of(context).extension<StackColors>()!.textDark,
                ),
              ),
            ],
          ),
          const SizedBox(height: 10),
          Row(
            children: [
              const SizedBox(
                width: 12 + 32, // space + size of WalletInfoCoinIcon
              ),
              Text(
                "Spark",
                style: STextStyles.desktopTextExtraExtraSmall(context).copyWith(
                  color: Theme.of(context).extension<StackColors>()!.textDark,
                ),
              ),
              const Spacer(),
              _BalanceDisplay(walletId: walletId, balanceType: .private),
              const SizedBox(width: 80),
              CustomTextButton(
                text: "Select wallet",
                onTap: () async {
                  Future<String?> _future() async {
                    final wallet =
                        ref.read(pWallets).getWallet(walletId)
                            as SparkInterface;

                    final sparkAddress = await wallet
                        .getCurrentReceivingSparkAddress();
                    if (sparkAddress != null) {
                      return sparkAddress.value;
                    }

                    return (await wallet.generateNextSparkAddress(
                      saveToDB: true,
                    )).value;
                  }

                  Exception? ex;
                  final sparkAddress = await showLoading(
                    context: context,
                    message: "Fetching Spark address",
                    rootNavigator: Util.isDesktop,
                    delay: const Duration(milliseconds: 1200),
                    whileFutureAlt: _future,
                    onException: (e) => ex = e,
                  );

                  if (context.mounted) {
                    if (ex != null) {
                      await showDialog<void>(
                        context: context,
                        builder: (context) => StackOkDialog(
                          title: "Error",
                          message: ex
                              .toString()
                              .replaceFirst("Exception:", "")
                              .trim(),
                          maxWidth: 400,
                          desktopPopRootNavigator: true,
                        ),
                      );
                    } else {
                      Navigator.of(context).pop(
                        sparkAddress == null
                            ? null
                            : Tuple2(
                                "${ref.read(pWalletName(walletId))} (Spark)",
                                sparkAddress,
                              ),
                      );
                    }
                  }
                },
              ),
            ],
          ),
          const SizedBox(height: 10),
          Row(
            children: [
              const SizedBox(
                width: 12 + 32, // space + size of WalletInfoCoinIcon
              ),
              Text(
                "Transparent",
                style: STextStyles.desktopTextExtraExtraSmall(context).copyWith(
                  color: Theme.of(context).extension<StackColors>()!.textDark,
                ),
              ),
              const Spacer(),
              _BalanceDisplay(walletId: walletId, balanceType: .public),
              const SizedBox(width: 80),
              CustomTextButton(
                text: "Select wallet",
                onTap: () async {
                  final wallet = ref.read(pWallets).getWallet(walletId);
                  final address =
                      (await wallet.getCurrentReceivingAddress())?.value ??
                      wallet.info.cachedReceivingAddress;

                  if (context.mounted) {
                    Navigator.of(
                      context,
                    ).pop(Tuple2("${wallet.info.name} (Transparent)", address));
                  }
                },
              ),
            ],
          ),
        ],
      ),
    );
  }
}
